import { getReq } from '@meli/server-context';

type WrapperProps = {
  id?: string;
  className: string;
};

export function getWrapperProps(): WrapperProps | undefined {
  const { id, className } = getReq().nordicPages?.pageSettings ?? {};

  if (!className) {
    return undefined;
  }

  return { id, className };
}
